import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import "./Homebage.css";

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <nav className={`navbar ${scrolled ? "scrolled" : ""}`}>
      <div className="navbar-container">
        
        {/* Logo */}
        <div className="navbar-logo">
          <span className="logo-icon">🎓</span>
          <span className="logo-text">مستشارك الأكاديمي الذكي</span>
        </div>

        {/* Links */}
        <div className="navbar-links">
          <a href="#" className="nav-link">تحميل التطبيق</a>

          <Link to="/login" className="nav-link">
            تسجيل دخول
          </Link>

          <button className="btn-primary glow-btn">
            ابدأ الاختبار
          </button>

          <span className="hamburger">☰</span>
        </div>
      </div>
    </nav>
  );
};

const HeroSection = () => (
  <section className="hero">
    <div className="hero-container">
      
      <div className="hero-text">
        <h1 className="hero-title">
          اكتشف تخصصك الذكي
          <br />
          <span className="highlight">مع مساعدك AI</span>
        </h1>

        <p className="hero-subtitle">
          تحليل ميولك ومهاراتك باستخدام الذكاء الاصطناعي لاختيار أفضل تخصص لك
        </p>

        {/* ✅ تم التعديل هون */}
        <div className="hero-buttons">
          <button className="btn-green">ابدأ التحليل 🚀</button>

          <Link to="/login" className="btn-outline">
            جرّب الآن
          </Link>
        </div>
      </div>

      <div className="hero-illustration">
        <div className="illustration-blob"></div>

        <div className="robot-card">
          🤖
          <p>AI Advisor</p>
        </div>

        <div className="student-card">🧑‍💻</div>

        <div className="floating-card card-1">💡</div>
        <div className="floating-card card-2">📊</div>
        <div className="floating-card card-3">🎯</div>
      </div>
    </div>
  </section>
);

const HowItWorks = () => {
  const cards = [
    {
      icon: "⚙️",
      title: "تحليل فوري",
      desc: "نحلل مهاراتك خلال ثواني",
    },
    {
      icon: "🔍",
      title: "اقتراح تخصص",
      desc: "نقترح عليك أفضل تخصص يناسبك",
    },
    {
      icon: "🤖",
      title: "ذكاء اصطناعي",
      desc: "تحليل متقدم مبني على AI",
    },
  ];

  return (
    <section className="how-it-works">
      <h2 className="section-title">كيف يعمل الموقع؟</h2>

      <div className="cards-grid">
        {cards.map((card, i) => (
          <div className="feature-card" key={i}>
            <div className="card-icon">{card.icon}</div>
            <h3 className="card-title">{card.title}</h3>
            <p className="card-desc">{card.desc}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

const ComparisonBanner = () => (
  <section className="comparison-banner">
    <div className="comparison-inner">
      <div className="comp-right">
        <span className="comp-icon">🎓</span>
        <span>علوم الحاسوب</span>
      </div>

      <div className="vs-circle">VS</div>

      <div className="comp-left">
        <span className="comp-icon">🤖</span>
        <span>الذكاء الاصطناعي</span>
      </div>
    </div>
  </section>
);

const ChatbotButton = () => (
  <button className="chatbot-btn pulse">💬</button>
);

const YazanHomePage = () => {
  return (
    <div className="app" dir="rtl">
      <Navbar />
      <HeroSection />
      <HowItWorks />
      <ComparisonBanner />
      <ChatbotButton />
    </div>
  );
};

export default YazanHomePage;
